select
id, club_type, income_expend, project_id, project_name, subject_code, subject_name, budget, income_amount,
membership_fee, write_off, expend_time, remark, create_time, update_time
from tb_club_bill_detail


        and id = #{query.id}


        and club_type = #{query.clubType}


        and income_expend = #{query.incomeExpend}


        and project_id = #{query.projectId}


        and project_name = #{query.projectName}


        and subject_code = #{query.subjectCode}


        and subject_name = #{query.subjectName}


        and budget = #{query.budget}


        and income_amount = #{query.incomeAmount}


        and membership_fee = #{query.membershipFee}


        and write_off = #{query.writeOff}


        and expend_time = #{query.expendTime}


        and remark = #{query.remark}


        and create_time = #{query.createTime}


        and update_time = #{query.updateTime}



    limit #{offset}, #{pageSize}

select count(1)
from tb_club_bill_detail


        and id = #{query.id}


        and club_type = #{query.clubType}


        and income_expend = #{query.incomeExpend}


        and project_id = #{query.projectId}


        and project_name = #{query.projectName}


        and subject_code = #{query.subjectCode}


        and subject_name = #{query.subjectName}


        and budget = #{query.budget}


        and income_amount = #{query.incomeAmount}


        and membership_fee = #{query.membershipFee}


        and write_off = #{query.writeOff}


        and expend_time = #{query.expendTime}


        and remark = #{query.remark}


        and create_time = #{query.createTime}


        and update_time = #{query.updateTime}

SELECT club_type AS clubName, SUM(budget) AS budget, SUM(CASE WHEN income_expend = 1 THEN income_amount ELSE 0 END) AS income, SUM(CASE WHEN income_expend = 2 THEN budget + income_amount ELSE 0 END) AS expend, (SUM(CASE WHEN income_expend = 1 THEN income_amount ELSE 0 END) - SUM(CASE WHEN income_expend = 2 THEN budget + income_amount ELSE 0 END)) AS balance FROM tb_club_bill_detail GROUP BY club_type
UNION ALL
SELECT '合计' AS clubName, SUM(budget) AS budget, SUM(CASE WHEN income_expend = 1 THEN income_amount ELSE 0 END) AS income, SUM(CASE WHEN income_expend = 2 THEN budget + income_amount ELSE 0 END) AS expend, (SUM(CASE WHEN income_expend = 1 THEN income_amount ELSE 0 END) - SUM(CASE WHEN income_expend = 2 THEN budget + income_amount ELSE 0 END)) AS balance FROM tb_club_bill_detail;
